import heapq
from collections import defaultdict

class Node:
    def __init__(self, char, freq, left=None, right=None):
        self.char = char
        self.freq = freq
        self.left = left
        self.right = right

    def __lt__(self, other):
        return self.freq < other.freq

def build_frequency_map(text):
    freq_map = defaultdict(int)
    for char in text:
        freq_map[char] += 1
    return freq_map

def build_huffman_tree(freq_map):
    priority_queue = []
    for char, freq in freq_map.items():
        heapq.heappush(priority_queue, Node(char, freq))

    if not priority_queue:
        return None

    if len(priority_queue) == 1:
        return heapq.heappop(priority_queue)

    while len(priority_queue) > 1:
        node1 = heapq.heappop(priority_queue)
        node2 = heapq.heappop(priority_queue)

        merged_node = Node(None, node1.freq + node2.freq, node1, node2)
        heapq.heappush(priority_queue, merged_node)

    return heapq.heappop(priority_queue)

def generate_huffman_codes(node, current_code, codes):
    if node is None:
        return

    if node.char is not None:
        codes[node.char] = current_code if current_code else "0"
        return

    generate_huffman_codes(node.left, current_code + "0", codes)
    generate_huffman_codes(node.right, current_code + "1", codes)

def encode_text(text, codes):
    encoded_text = "".join(codes[char] for char in text)
    return encoded_text

def decode_text(encoded_text, root):
    if not encoded_text and root is None:
        return ""

    if root and root.char is not None:
        if encoded_text:
            return root.char * len(encoded_text)
        else:
            return ""

    decoded_text = []
    current_node = root

    for bit in encoded_text:
        if bit == '0':
            current_node = current_node.left
        else:
            current_node = current_node.right

        if current_node.char is not None:
            decoded_text.append(current_node.char)
            current_node = root

    return "".join(decoded_text)

def huffman_encode(text):
    if not text:
        return "", {}, None

    freq_map = build_frequency_map(text)
    root = build_huffman_tree(freq_map)

    codes = {}
    if root:
        generate_huffman_codes(root, "", codes)

    encoded_text = encode_text(text, codes)
    return encoded_text, codes, root

def huffman_decode(encoded_text, root):
    return decode_text(encoded_text, root)
